css:
.hover-lift {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  cursor: pointer;
}
.hover-lift:hover {
  transform: translateY(-6px);
  box-shadow: 0 12px 40px rgba(0,0,0,0.15), 0 4px 12px rgba(0,0,0,0.08);
}

.hover-glow {
  border-radius: 12px;
  transition: all 0.3s ease;
  cursor: pointer;
}
.hover-glow:hover {
  box-shadow: 0 0 0 2px #B8FB3C, 0 0 20px rgba(184,251,60,0.3), 0 0 40px rgba(184,251,60,0.15);
}

.hover-shimmer {
  position: relative;
  overflow: hidden;
  cursor: pointer;
}
.hover-shimmer::after {
  content: '';
  position: absolute;
  inset: -100%;
  background: linear-gradient(105deg, transparent 30%, rgba(255,255,255,0.15) 50%, transparent 70%);
  transition: transform 0.6s ease;
  transform: translateX(-100%);
}
.hover-shimmer:hover::after { transform: translateX(100%); }

.hover-fill {
  position: relative;
  overflow: hidden;
  cursor: pointer;
  transition: color 0.3s ease;
}
.hover-fill::before {
  content: '';
  position: absolute;
  inset: 0;
  background: #B8FB3C;
  transform: translateY(100%);
  transition: transform 0.35s cubic-bezier(0.4,0,0.2,1);
  z-index: 0;
}
.hover-fill:hover::before { transform: translateY(0); }
.hover-fill > * { position: relative; z-index: 1; }
.hover-fill:hover { color: #0a0a0f; }

.hover-scale {
  transition: transform 0.25s cubic-bezier(0.34, 1.56, 0.64, 1);
  cursor: pointer;
}
.hover-scale:hover { transform: scale(1.05); }

.hover-underline {
  position: relative;
  display: inline-block;
  cursor: pointer;
}
.hover-underline::after {
  content: '';
  position: absolute;
  bottom: -2px;
  left: 50%; right: 50%;
  height: 2px;
  background: #B8FB3C;
  transition: all 0.3s ease;
}
.hover-underline:hover::after { left: 0; right: 0; }

.hover-neon-border {
  border: 2px solid transparent;
  border-radius: 12px;
  transition: all 0.3s ease;
  cursor: pointer;
}
.hover-neon-border:hover {
  border-color: #B8FB3C;
  box-shadow: 0 0 6px #B8FB3C, 0 0 12px rgba(184,251,60,0.5), inset 0 0 6px rgba(184,251,60,0.1);
}

.hover-rotate {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
  cursor: pointer;
}
.hover-rotate:hover { transform: rotate(45deg); }

.hover-border-draw {
  position: relative;
  cursor: pointer;
}
.hover-border-draw::before,
.hover-border-draw::after {
  content: '';
  position: absolute;
  width: 0; height: 0;
  transition: all 0.3s ease;
}
.hover-border-draw::before { top: 0; left: 0; border-top: 2px solid #B8FB3C; border-right: 2px solid #B8FB3C; }
.hover-border-draw::after { bottom: 0; right: 0; border-bottom: 2px solid #B8FB3C; border-left: 2px solid #B8FB3C; }
.hover-border-draw:hover::before,
.hover-border-draw:hover::after { width: 100%; height: 100%; }

.flip-card { perspective: 1000px; cursor: pointer; }
.flip-inner {
  position: relative;
  transform-style: preserve-3d;
  transition: transform 0.6s cubic-bezier(0.4,0.2,0.2,1);
}
.flip-card:hover .flip-inner { transform: rotateY(180deg); }
.flip-front, .flip-back {
  position: absolute; inset: 0;
  backface-visibility: hidden;
  border-radius: 16px;
}
.flip-back {
  transform: rotateY(180deg);
  background: linear-gradient(135deg, #B8FB3C, #06b6d4);
}

.hover-reveal {
  position: relative;
  overflow: hidden;
  cursor: pointer;
}
.hover-reveal .default { transition: all 0.25s ease; }
.hover-reveal .on-hover {
  position: absolute; inset: 0;
  display: flex; align-items: center; justify-content: center;
  opacity: 0; filter: blur(4px);
  transition: all 0.25s ease;
}
.hover-reveal:hover .default { opacity: 0; filter: blur(4px); }
.hover-reveal:hover .on-hover { opacity: 1; filter: blur(0); }

.hover-ripple { position: relative; overflow: hidden; cursor: pointer; }
.ripple-circle {
  position: absolute;
  border-radius: 50%;
  transform: scale(0);
  animation: ripple-expand 0.6s linear;
  background: rgba(255,255,255,0.3);
  pointer-events: none;
}
@keyframes ripple-expand { to { transform: scale(4); opacity: 0; } }

.hover-tilt {
  transition: transform 0.15s ease;
  transform-style: preserve-3d;
  cursor: pointer;
}
/* JS: track mouse and apply rotateX/Y transforms */

.hover-spotlight {
  position: relative;
  overflow: hidden;
  cursor: pointer;
}
.hover-spotlight::before {
  content: '';
  position: absolute;
  width: 200px; height: 200px;
  background: radial-gradient(circle, rgba(255,255,255,0.15) 0%, transparent 70%);
  border-radius: 50%;
  transform: translate(-50%, -50%);
  pointer-events: none;
  opacity: 0;
  transition: opacity 0.2s ease;
}
.hover-spotlight:hover::before { opacity: 1; }
/* JS: update left/top from mousemove event */

.hover-magnetic {
  transition: transform 0.2s ease;
  cursor: pointer;
  display: inline-block;
}
/* JS: calculate offset from element center and apply translateX/Y */
